import React, { useState } from "react";
import InstructionBox from "../InstructionBox";
import "../../styles/modes.css";

const VisualEquivalence = () => {
  const [currentLevel, setCurrentLevel] = useState(0);

  const equivalences = [
    {
      title: "Halves to Fourths",
      left: { pieces: 2, filled: 1, label: "1/2", color: "#6366F1" },
      right: { pieces: 4, filled: 2, label: "2/4", color: "#6366F1" },
      message: "1/2 = 2/4 ✨",
      explanation: "We cut 1 piece in HALF. Now we have 2 pieces instead of 1, but the colored amount is the SAME! More pieces, same amount. 🍕",
      details: "If you have 1/2 of a pizza and cut it in half, you get 2 pieces. But you still have the same amount of pizza to eat!"
    },
    {
      title: "Halves to Eighths",
      left: { pieces: 2, filled: 1, label: "1/2", color: "#10B981" },
      right: { pieces: 8, filled: 4, label: "4/8", color: "#10B981" },
      message: "1/2 = 4/8 ✨",
      explanation: "We cut each piece into 4 tiny pieces. 1 piece becomes 4 pieces, but the colored amount stays the SAME! 🔪",
      details: "1/2 of the pizza cut into tiny pieces = 4/8 of the pizza. Same delicious pizza, just more pieces!"
    },
    {
      title: "Thirds to Sixths",
      left: { pieces: 3, filled: 1, label: "1/3", color: "#EF4444" },
      right: { pieces: 6, filled: 2, label: "2/6", color: "#EF4444" },
      message: "1/3 = 2/6 ✨",
      explanation: "We cut 1 piece in HALF. Now we have 2 pieces instead of 1, but the colored amount is the SAME! 🎂",
      details: "1/3 of the cake cut in half = 2/6 of the cake. Same amount of cake, just more slices!"
    },
    {
      title: "Two-Thirds to Sixths",
      left: { pieces: 3, filled: 2, label: "2/3", color: "#F59E0B" },
      right: { pieces: 6, filled: 4, label: "4/6", color: "#F59E0B" },
      message: "2/3 = 4/6 ✨",
      explanation: "We cut each piece in HALF. 2 pieces become 4 pieces, but the colored amount is the SAME! 🧁",
      details: "2/3 of a chocolate bar cut in half = 4/6 of the chocolate bar. Same chocolate, just more tiny pieces!"
    },
    {
      title: "Fourths to Eighths",
      left: { pieces: 4, filled: 1, label: "1/4", color: "#8B5CF6" },
      right: { pieces: 8, filled: 2, label: "2/8", color: "#8B5CF6" },
      message: "1/4 = 2/8 ✨",
      explanation: "We cut 1 piece in HALF. Now we have 2 pieces instead of 1, but the colored amount is the SAME! ✂️",
      details: "1/4 of an apple cut in half = 2/8 of the apple. Same piece of apple, just cut into smaller bites!"
    },
    {
      title: "Halves to Sixths",
      left: { pieces: 2, filled: 1, label: "1/2", color: "#EC4899" },
      right: { pieces: 6, filled: 3, label: "3/6", color: "#EC4899" },
      message: "1/2 = 3/6 ✨",
      explanation: "We cut each piece into 3 parts. 1 piece becomes 3 pieces, but the colored amount stays the SAME! 🍪",
      details: "1/2 of a cookie cut into thirds = 3/6 of the cookie. Same cookie, just more crumbles!"
    },
    {
      title: "Thirds to Ninths",
      left: { pieces: 3, filled: 1, label: "1/3", color: "#06B6D4" },
      right: { pieces: 9, filled: 3, label: "3/9", color: "#06B6D4" },
      message: "1/3 = 3/9 ✨",
      explanation: "We cut each piece into 3 parts. 1 piece becomes 3 pieces, but the colored amount stays the SAME! 🍰",
      details: "1/3 of a donut cut into thirds = 3/9 of the donut. Same delicious donut, just more bites!"
    },
    {
      title: "Two-Fourths to Eighths",
      left: { pieces: 4, filled: 2, label: "2/4", color: "#14B8A6" },
      right: { pieces: 8, filled: 4, label: "4/8", color: "#14B8A6" },
      message: "2/4 = 4/8 ✨",
      explanation: "We cut each piece in HALF. 2 pieces become 4 pieces, but the colored amount is the SAME! 🥧",
      details: "2/4 of a pie cut in half = 4/8 of the pie. Same pie, just more slices!"
    },
    {
      title: "One Fourth to Six Twelfths",
      left: { pieces: 4, filled: 1, label: "1/4", color: "#F97316" },
      right: { pieces: 12, filled: 3, label: "3/12", color: "#F97316" },
      message: "1/4 = 3/12 ✨",
      explanation: "We cut each piece into 3 parts. 1 piece becomes 3 pieces, but the colored amount stays the SAME! 🍫",
      details: "1/4 of a chocolate bar cut into thirds = 3/12 of the chocolate bar. Same chocolate, just tinier pieces!"
    },
    {
      title: "One Third to Four Twelfths",
      left: { pieces: 3, filled: 1, label: "1/3", color: "#6366F1" },
      right: { pieces: 12, filled: 4, label: "4/12", color: "#6366F1" },
      message: "1/3 = 4/12 ✨",
      explanation: "We cut each piece into 4 parts. 1 piece becomes 4 pieces, but the colored amount stays the SAME! 🎁",
      details: "1/3 of a gift cut into quarters = 4/12 of the gift. Same gift, just more pieces to unwrap!"
    },
  ];

  const level = equivalences[currentLevel];

  const renderBoxes = (pieces, filled, color) => {
    return (
      <div className="boxes-container">
        {Array.from({ length: pieces }).map((_, i) => (
          <div
            key={i}
            className="box-segment"
            style={{
              backgroundColor: i < filled ? color : "#E5E7EB",
              border: `2px solid ${color}`,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              position: "relative",
              overflow: "hidden",
            }}
          >
            <span
              style={{
                fontSize: "1.2rem",
                fontWeight: "700",
                color: i < filled ? "white" : "rgba(156, 163, 175, 0.5)",
                textShadow: i < filled ? "0 1px 2px rgba(0,0,0,0.2)" : "none",
              }}
            >
              {i + 1}
            </span>
          </div>
        ))}
      </div>
    );
  };

  const nextLevel = () => {
    if (currentLevel < equivalences.length - 1) {
      setCurrentLevel(currentLevel + 1);
    }
  };

  const prevLevel = () => {
    if (currentLevel > 0) {
      setCurrentLevel(currentLevel - 1);
    }
  };

  return (
    <div className="mode-container">
      <InstructionBox
        title="Visual Equivalence"
        description="Different fractions can show the SAME amount! 🤯"
      />

      <div className="equivalence-display">
        <div className="equivalence-pair">
          <div className="fraction-container">
            <div className="fraction-label">{level.left.label}</div>
            {renderBoxes(level.left.pieces, level.left.filled, level.left.color)}
          </div>

          <div className="equals-sign">
            <span>=</span>
          </div>

          <div className="fraction-container">
            <div className="fraction-label">{level.right.label}</div>
            {renderBoxes(level.right.pieces, level.right.filled, level.right.color)}
          </div>
        </div>
      </div>

      <div className="equivalence-message">
        <h2 style={{ fontSize: "2rem", color: level.left.color }}>
          {level.message}
        </h2>
        <p style={{ fontSize: "1.1rem", color: "#6B7280", marginTop: "12px" }}>
          Count the <strong>colored boxes</strong>. Now count the <strong>gray boxes</strong>. The colored part is the SAME SIZE in both, even though the pieces are cut differently!
        </p>
        <p style={{ fontSize: "1.1rem", color: level.left.color, marginTop: "16px", fontWeight: "700", backgroundColor: "rgba(255,255,255,0.7)", padding: "12px", borderRadius: "8px" }}>
          💡 {level.explanation}
        </p>
        <p style={{ fontSize: "1rem", color: "#6B7280", marginTop: "12px", fontStyle: "italic", backgroundColor: "#F9FAFB", padding: "12px", borderRadius: "8px", borderLeft: `4px solid ${level.left.color}` }}>
          📖 {level.details}
        </p>
      </div>

      <div className="level-progress">
        <span style={{ fontSize: "1.1rem", fontWeight: "700" }}>
          Level {currentLevel + 1} of {equivalences.length}
        </span>
        <div className="progress-bar">
          <div
            className="progress-fill"
            style={{ width: `${((currentLevel + 1) / equivalences.length) * 100}%` }}
          />
        </div>
      </div>

      <div className="button-group">
        <button
          onClick={prevLevel}
          disabled={currentLevel === 0}
          className="btn-modern-primary"
          style={{ opacity: currentLevel === 0 ? 0.5 : 1 }}
        >
          ← Previous
        </button>
        <button onClick={nextLevel} disabled={currentLevel === equivalences.length - 1} className="btn-modern-primary" style={{ opacity: currentLevel === equivalences.length - 1 ? 0.5 : 1 }}>
          Next →
        </button>
      </div>

      {currentLevel === equivalences.length - 1 && (
        <div className="message-box">
          <h3 style={{ color: "#10B981", fontSize: "1.5rem" }}>
            🎉 You learned equivalence!
          </h3>
          <p>When you cut pieces smaller, you get MORE pieces, but the COLORED PART stays the SAME! That's why different fractions can mean the same amount!</p>
        </div>
      )}
    </div>
  );
};

export default VisualEquivalence;
